// Black Hole — Cinematic Display (dual crossing + gravitationally lensed star field)
//
// Deflection map layout:
//   output1: (final_r, disk1_r, cos_angle1, sin_angle1)
//   output2: (vol_accum, disk2_r, cos_angle2, sin_angle2)
//   output3: (sky_dir.xyz, escaped_flag)
//
// Shading model: the accretion disk is OPTICALLY THIN LUMINOUS PLASMA.
// Emission and opacity both derive from one material density field —
// where there is little light there is also little occlusion, so dim
// regions dissolve into the star field instead of reading as opaque
// paint. (The previous model composited the disk as a uniformly opaque
// annulus with a dim albedo, which rendered as a matte clay saucer;
// every prior fix patched that model's edge artifacts rather than the
// model. Don't reintroduce a fixed-opacity annulus.)
//
// Compositing is back-to-front along the ray: star field → lensed back
// crossing → photon ring → volumetric sheen → front crossing.

struct Uniforms {
    time_val: f32,
    disk_inner: f32,
    disk_outer: f32,
    disk_glow: f32,
    stars_brightness: f32,
    spin: f32,
    shear_speed: f32,
    rotate_rad: f32,
    cam_dist: f32,
    tilt_rad: f32,
    roll_rad: f32,
    uv_scale: f32,
    aspect: f32,
    cam_velocity: f32,
    cam_freefall: f32,
    doppler_amt: f32,
    temperature: f32,
    flare_gain: f32,
    flare_env: f32,
    flare_seed: f32,
    _pad0: f32,
};

@group(0) @binding(0) var<uniform> u: Uniforms;
@group(0) @binding(1) var deflection1: texture_2d<f32>;
@group(0) @binding(2) var deflection2: texture_2d<f32>;
@group(0) @binding(3) var s_linear: sampler;
@group(0) @binding(4) var output: texture_storage_2d<rgba16float, write>;
@group(0) @binding(5) var sky_dir_tex: texture_2d<f32>;

// ── Hash functions ──

fn hash21(p: vec2<f32>) -> f32 {
    var p3 = fract(vec3<f32>(p.x, p.y, p.x) * 0.1031);
    p3 += dot(p3, p3.yzx + 33.33);
    return fract((p3.x + p3.y) * p3.z);
}

fn noise2d(p: vec2<f32>) -> f32 {
    let i = floor(p);
    let f = fract(p);
    let u2 = f * f * (3.0 - 2.0 * f);
    return mix(
        mix(hash21(i), hash21(i + vec2<f32>(1.0, 0.0)), u2.x),
        mix(hash21(i + vec2<f32>(0.0, 1.0)), hash21(i + vec2<f32>(1.0, 1.0)), u2.x),
        u2.y,
    );
}

fn fbm(p: vec2<f32>) -> f32 {
    var val = noise2d(p) * 0.5;
    val += noise2d(p * 2.03 + vec2<f32>(1.7, -1.3)) * 0.25;
    val += noise2d(p * 4.07 + vec2<f32>(3.4, -2.6)) * 0.125;
    return val;
}

// ── Procedural star field ──

fn star_layer(theta: f32, phi: f32, scale: f32, threshold: f32,
              intensity_mult: f32, seed: f32) -> vec3<f32> {
    let uv = vec2<f32>(phi * scale * 0.15915, theta * scale * 0.31831);
    let cell = floor(uv);
    let f = fract(uv);

    var light = vec3<f32>(0.0);

    for (var j = -1; j <= 1; j++) {
        for (var i = -1; i <= 1; i++) {
            let neighbor = cell + vec2<f32>(f32(i), f32(j));
            let h = hash21(neighbor + seed);
            if h > threshold {
                let sx = hash21(neighbor * 1.273 + seed + 7.0);
                let sy = hash21(neighbor * 2.178 + seed + 13.0);
                let d = f - vec2<f32>(f32(i), f32(j)) - vec2<f32>(sx, sy);
                let dist2 = dot(d, d);

                // Steeper power law — many faint, very few bright
                let norm_bright = (h - threshold) / (1.0 - threshold);
                let star_intensity = pow(norm_bright, 1.5) * intensity_mult;

                // Tight point spread — sharp pinpoints, not blobs
                let core = exp(-dist2 * 6000.0);
                let halo = exp(-dist2 * 800.0) * norm_bright * norm_bright * 0.06;

                // Desaturated spectral colors — subtle tint, mostly white
                let temp = hash21(neighbor * 3.46 + seed + 27.0);
                var star_col: vec3<f32>;
                if temp > 0.82 {
                    star_col = vec3<f32>(0.88, 0.92, 1.15);  // O/B cool blue tint
                } else if temp > 0.55 {
                    star_col = vec3<f32>(0.97, 0.98, 1.05);  // A/F near-white
                } else if temp > 0.25 {
                    star_col = vec3<f32>(1.0, 0.97, 0.93);   // G solar
                } else {
                    star_col = vec3<f32>(1.05, 0.92, 0.82);  // K/M warm tint
                }

                light += star_col * star_intensity * (core + halo);
            }
        }
    }
    return light;
}

fn star_field(dir: vec3<f32>, brightness: f32) -> vec3<f32> {
    if brightness < 0.001 { return vec3<f32>(0.0); }

    let theta = acos(clamp(dir.y, -1.0, 1.0));
    let phi = atan2(dir.z, dir.x) + 3.14159265;

    var stars = vec3<f32>(0.0);

    // Layer 1: bright stars
    stars += star_layer(theta, phi, 20.0, 0.82, 3.0, 0.0);

    // Layer 2: medium density
    stars += star_layer(theta, phi, 50.0, 0.80, 1.2, 100.0);

    // Layer 3: dense field
    stars += star_layer(theta, phi, 100.0, 0.84, 0.5, 200.0);

    // Layer 4: faint background dust
    stars += star_layer(theta, phi, 180.0, 0.88, 0.15, 300.0);

    return stars * brightness;
}

// ── Accretion disk shading — optically thin luminous plasma ──

// Radial extent of disk MATERIAL, noise-free — used to bound every
// disk-derived term. The deflection bake records plane crossings and
// accumulates the volumetric path integral over generous fixed bounds
// (0.5..25 r_s) with NO knowledge of disk_inner/outer; unbounded, the
// volumetric term paints a smooth elliptical halo out to r≈25 that
// reads as a solid saucer twice the disk's size (that halo — not the
// disk — was most of the old look's visible area).
fn radial_envelope(disk_r: f32) -> f32 {
    let inner_edge = smoothstep(u.disk_inner * 0.70, u.disk_inner * 1.04, disk_r);
    let outer_edge = 1.0 - smoothstep(u.disk_outer * 0.60, u.disk_outer * 1.05, disk_r);
    return inner_edge * outer_edge;
}

// Temperature palette, inner→outer. Every stop is luminous — warm white
// through amber to saturated ember. Dimness comes from the brightness
// envelope and alpha, never from a dark albedo: dim brown at full
// opacity is exactly the matte-saucer failure this model replaces.
fn disk_palette(t: f32) -> vec3<f32> {
    let white  = vec3<f32>(1.30, 1.20, 1.05);
    let gold   = vec3<f32>(1.28, 0.84, 0.40);
    let orange = vec3<f32>(1.12, 0.48, 0.14);
    let ember  = vec3<f32>(0.92, 0.26, 0.06);
    if t < 0.18 {
        return mix(white, gold, t / 0.18);
    } else if t < 0.55 {
        return mix(gold, orange, (t - 0.18) / 0.37);
    }
    return mix(orange, ember, clamp((t - 0.55) / 0.45, 0.0, 1.0));
}

// One filament-noise sample. The fbm domain is a circle embedding
// (cos/sin of the sheared azimuth — seam-free in angle) that moves
// SLOWLY around the circle and FAST along log-radius, which stretches
// the noise into the long thin azimuthal arcs differential rotation
// actually produces. `wind` is the differential-rotation phase offset.
fn filament_layer(base_angle: f32, rigid: f32, wind: f32, lr: f32) -> f32 {
    let phase = base_angle + rigid + wind;
    let cs = cos(phase);
    let ss = sin(phase);
    let f_coarse = fbm(vec2<f32>(cs * 1.5 + lr * 6.5, ss * 1.5 - lr * 3.7));
    let f_fine = fbm(vec2<f32>(
        cs * 3.0 + lr * 14.0 + 41.7,
        ss * 3.0 - lr * 7.9 + 13.3,
    ));
    return f_coarse * 0.62 + f_fine * 0.38;
}

struct DiskSample {
    emission: vec3<f32>,
    alpha: f32,
};

fn shade_disk(disk_r: f32, cos_a: f32, sin_a: f32) -> DiskSample {
    let r_norm = disk_r / u.disk_inner; // 1.0 at the inner edge
    let t = clamp(
        (disk_r - u.disk_inner) / (u.disk_outer - u.disk_inner),
        0.0, 1.0,
    );
    let base_angle = atan2(sin_a, cos_a);
    let lr = log(max(r_norm, 0.25));

    // ── Keplerian differential shear, flow-map style ──
    // Material at radius r orbits at ω ∝ r^-3/2, so inner filaments
    // overtake outer ones — that's the churn, and the Speed slider
    // drives it (shear_speed). Unbounded shear winds the pattern into
    // mush over minutes, so the differential part runs on two sawtooth
    // time offsets crossfaded by a triangle weight (classic flow-map
    // rewind): each layer's winding is bounded at ±PERIOD/2 and the
    // crossfade hides every rewind. The rigid part rotates the whole
    // pattern and never winds, so it stays unbounded.
    let rigid = u.time_val * (0.02 + u.shear_speed * 0.06);
    let wind_rate = (0.10 + u.shear_speed * 0.45) / (r_norm * sqrt(r_norm));
    let period = 24.0;
    let ph_a = fract(u.time_val / period);
    let ph_b = fract(u.time_val / period + 0.5);
    let w_a = 1.0 - abs(2.0 * ph_a - 1.0);
    let f_a = filament_layer(base_angle, rigid, (ph_a - 0.5) * period * wind_rate, lr);
    let f_b = filament_layer(base_angle, rigid, (ph_b - 0.5) * period * wind_rate, lr);
    let f_raw = mix(f_b, f_a, w_a);
    let filaments = smoothstep(0.16, 0.72, f_raw);

    // ── Radial density envelope ──
    // Soft inner edge just inside ISCO; ragged outer rim — the nominal
    // outer radius is modulated by slow angular noise (rigid-rotating,
    // outside the shear crossfade so the rim doesn't breathe) and the
    // falloff starts well inside it, so the silhouette dissolves into
    // streak tails instead of ending on a compass-drawn circle.
    let rim_cs = cos(base_angle + rigid);
    let rim_ss = sin(base_angle + rigid);
    let rim_noise = fbm(vec2<f32>(rim_cs * 2.2 + 71.0, rim_ss * 2.2 + 37.0));
    let inner_edge = smoothstep(u.disk_inner * 0.70, u.disk_inner * 1.04, disk_r);
    let r_out_eff = u.disk_outer * (0.90 + 0.32 * rim_noise);
    let outer_edge = 1.0 - smoothstep(r_out_eff * 0.55, r_out_eff, disk_r);
    let envelope = inner_edge * outer_edge;

    let density = envelope * (0.10 + 1.15 * filaments);

    // ── Doppler beaming ── the approaching side is at 90° to the
    // camera azimuth (material orbits counterclockwise, tangent
    // (-sin φ, 0, cos φ); its line-of-sight speed toward a camera at
    // azimuth `rotate` is ∝ sin(rotate − φ)). The old cos(φ) form
    // boosted the lobe facing the camera — the wrong side, and it
    // didn't track camera rotation. Kept below physical strength —
    // Interstellar suppressed beaming too.
    let v_orb = 0.45 * inverseSqrt(r_norm) + u.spin * 0.12 / (r_norm * r_norm);
    let approach = sin(u.rotate_rad - base_angle);
    let raw_doppler = pow(max(1.0 + v_orb * approach, 0.05), 3.0);
    let doppler = mix(1.0, raw_doppler, u.doppler_amt);

    // ── Emission ── palette × radial brightness envelope × filament
    // brightness. Deliberately HDR: the inner edge peaks around
    // disk_glow × 2.4 (×doppler) and the downstream bloom/halation/EDR
    // pipeline is what turns that into light — values here sit above
    // the bloom prefilter on purpose. The radial exponent is far
    // shallower than physical (−1.3, not r^−3): Gargantua's disk reads
    // bright across most of its width, and the palette already carries
    // the cooling.
    // Temperature biases the palette along the same ramp (hotter = whiter,
    // cooler = deeper ember) and scales output — physically this is the
    // accretion rate: a disk feeding harder runs hotter and brighter. The
    // range stays inside the filmic amber band on purpose.
    let tc = clamp(t + (f_raw - 0.45) * 0.20 - u.temperature * 0.30, 0.0, 1.0);
    let bright = u.disk_glow * 2.4 * pow(r_norm, -1.3) * exp2(u.temperature * 0.8);
    var emission = disk_palette(tc) * bright * doppler
        * (0.15 + 1.85 * pow(filaments, 1.4)) * envelope;

    // Plunging region: faint hot gas spiraling in from the inner edge
    // toward the horizon — emission with only a whisper of occlusion.
    let plunge = (1.0 - smoothstep(u.disk_inner * 0.55, u.disk_inner * 1.0, disk_r))
        * smoothstep(u.disk_inner * 0.35, u.disk_inner * 0.55, disk_r);
    emission += vec3<f32>(1.05, 0.55, 0.22) * plunge * u.disk_glow * 0.35;

    // Doppler blueshift: the approaching side shifts toward white-blue as
    // beaming strengthens — breaks the all-amber palette exactly where the
    // physics does.
    let blue = clamp(v_orb * approach * u.doppler_amt, 0.0, 0.45);
    emission = emission * mix(vec3<f32>(1.0), vec3<f32>(0.80, 0.93, 1.30), max(blue, 0.0));

    // ── Flare — trigger-driven orbiting hot spot ──
    // Spawned by a trigger edge (envelope_decay snaps flare_env to 1 and
    // decays it); the spot lives in the material frame near the inner
    // edge, rides the Keplerian flow, and smears from a tight knot into
    // a sheared arc as the envelope dies — the way observed hot spots
    // (Sgr A* flares) actually behave.
    var flare_spot = 0.0;
    if u.flare_env > 0.001 && u.flare_gain > 0.001 {
        // Attack phase: the raw envelope snaps 0 -> 1 in one frame, and a
        // single-frame full-brightness pop reads as a glitch. Brightness
        // swells in over the envelope's first stretch (1.0 -> 0.76, about
        // 250 ms at the default decay rate) and only then follows the
        // decay out. The SHAPE still keys off the raw envelope so the
        // spot is born tight and smears as it ages.
        let fl_attack = smoothstep(1.0, 0.76, u.flare_env);
        let fl_bright = fl_attack * u.flare_env;
        let om = (0.10 + u.shear_speed * 0.45) / (r_norm * sqrt(r_norm));
        let d_ang = base_angle + u.time_val * om - u.flare_seed;
        let arc_tight = 2.0 + 22.0 * u.flare_env;
        let arc = exp((cos(d_ang) - 1.0) * arc_tight);
        // Sits in the amber mid-disk (~2.4x inner) — a knot at the inner
        // edge drowns invisibly in the white-hot band; out here it reads
        // against the disk body across the room.
        let dr = (disk_r - u.disk_inner * 2.4) / (u.disk_inner * 0.55);
        let radial = exp(-dr * dr);
        flare_spot = arc * radial * fl_bright * u.flare_gain;
        emission += vec3<f32>(1.40, 1.18, 0.85) * flare_spot * u.disk_glow * 8.0;
    }

    // Hue-preserving shoulder — bounds param-extreme spikes
    // (glow × doppler at slider maxima) without stepping on the HDR
    // range bloom needs. Same Reinhard-asymptote shape as before; the
    // cap is higher because the disk is now supposed to be bright.
    let max_b = max(emission.r, max(emission.g, emission.b));
    let cap = 12.0;
    if max_b > cap {
        let new_max = cap + (max_b - cap) / (1.0 + (max_b - cap) / cap);
        emission = emission * (new_max / max_b);
    }

    // ── Opacity coupled to the material, not to a fixed annulus ──
    // Beer–Lambert on the same density that drives emission: bright
    // filaments occlude (α ≈ 0.94), dark lanes go translucent
    // (α ≈ 0.3), streak tails fade to nothing.
    let alpha = 1.0 - exp(-density * 2.6);

    return DiskSample(emission, clamp(alpha + plunge * 0.15 + flare_spot * 0.25, 0.0, 1.0));
}

// ── Main ──

@compute @workgroup_size(16, 16)
fn cs_main(@builtin(global_invocation_id) gid: vec3<u32>) {
    let dims = textureDimensions(output);
    if gid.x >= dims.x || gid.y >= dims.y {
        return;
    }

    let uv = vec2<f32>(f32(gid.x) + 0.5, f32(gid.y) + 0.5)
        / vec2<f32>(f32(dims.x), f32(dims.y));

    // ── Sample pre-blurred deflection textures ──
    // The H+V separable gaussian compute passes already ran over the
    // deflection bake at quarter resolution, so by the time we get
    // here the textures contain a true 21-tap σ=4 gaussian-blurred
    // version of the deflection data. One bilinear tap each — the
    // entire wide-blur cost was paid at quarter-res.
    let d1 = textureSampleLevel(deflection1, s_linear, uv, 0.0);
    let d2 = textureSampleLevel(deflection2, s_linear, uv, 0.0);
    let sky = textureSampleLevel(sky_dir_tex, s_linear, uv, 0.0);

    let final_r = d1.r;
    let c1_r = d1.g;
    let c1_ca = d1.b;
    let c1_sa = d1.a;
    let c2_r = d2.g;
    let c2_ca = d2.b;
    let c2_sa = d2.a;

    // Crossing visibility: squared magnitude of (cos_a, sin_a) is ~1.0
    // for a real crossing, 0 for a non-crossing pixel; the quarter-res
    // gaussian produces fractional values at silhouette boundaries and
    // the smoothstep turns those into a soft fade.
    let c1_mag2 = c1_ca * c1_ca + c1_sa * c1_sa;
    let c1_visible = smoothstep(0.25, 0.85, c1_mag2);

    // ── Full-res near-field refinement of the front crossing ──
    // The bake is quarter-res and gaussian-blurred: right for the lensed
    // core (the data is smooth there and the blur hides texel structure),
    // but at close camera distances each bake texel magnifies across
    // dozens of screen pixels and the interpolated crossing coordinates
    // go visibly blocky. A ray that crosses the disk plane BEFORE it
    // comes near the hole hasn't bent yet, so its crossing is plain
    // ray–plane geometry — computed here per display pixel, exactly, and
    // blended in wherever the straight-line assumption holds. The camera
    // construction mirrors the deflection kernel's exactly (including
    // aberration); if you change one, change both.
    let ndc = (uv * 2.0 - 1.0) * u.uv_scale;
    let screen_flat = vec2<f32>(ndc.x * u.aspect, -ndc.y);
    let cr = cos(u.roll_rad);
    let sr = sin(u.roll_rad);
    let screen = vec2<f32>(
        screen_flat.x * cr - screen_flat.y * sr,
        screen_flat.x * sr + screen_flat.y * cr,
    );
    let safe_cam_dist = max(u.cam_dist, 0.05);
    let metric_factor = sqrt(max(1.0 - 1.0 / safe_cam_dist, 0.05));
    let fov_factor = 1.2 / metric_factor;
    let cos_tilt = cos(u.tilt_rad);
    let sin_tilt = sin(u.tilt_rad);
    let cos_rot = cos(u.rotate_rad);
    let sin_rot = sin(u.rotate_rad);
    let cam_pos = vec3<f32>(
        safe_cam_dist * cos_tilt * cos_rot,
        safe_cam_dist * sin_tilt,
        safe_cam_dist * cos_tilt * sin_rot,
    );
    let fwd = normalize(-cam_pos);
    let world_up = vec3<f32>(0.0, 1.0, 0.0);
    let cam_right = normalize(cross(fwd, world_up));
    let cam_up = cross(cam_right, fwd);
    var ray_dir = normalize(
        fwd + screen.x * cam_right * fov_factor + screen.y * cam_up * fov_factor);
    var beta = u.cam_velocity;
    if u.cam_freefall > 0.5 {
        beta = clamp(sqrt(1.0 / safe_cam_dist), 0.0, 0.99);
    }
    if beta > 1e-4 {
        let cos_tp = dot(ray_dir, fwd);
        let denom = 1.0 - beta * cos_tp;
        let cos_t = (cos_tp - beta) / denom;
        let sin_tp2 = max(1.0 - cos_tp * cos_tp, 0.0);
        let sin_t2 = max(1.0 - cos_t * cos_t, 0.0);
        let perp_scale = select(1.0, sqrt(sin_t2 / sin_tp2), sin_tp2 > 1e-8);
        let ray_perp = ray_dir - fwd * cos_tp;
        ray_dir = normalize(fwd * cos_t + ray_perp * perp_scale);
    }

    // Straight-line crossing of the disk plane; refined coords default to
    // the bake and blend toward the exact solution where the ray is still
    // straight at the crossing.
    var c1_rr = c1_r;
    var c1_car = c1_ca;
    var c1_sar = c1_sa;
    var c1_vis_r = c1_visible;
    if abs(ray_dir.y) > 1e-6 {
        let t_cross = -cam_pos.y / ray_dir.y;
        if t_cross > 0.0 {
            let p = cam_pos + ray_dir * t_cross;
            let r_a = length(p);
            // The geodesic only curves within a few miss-distances of its
            // closest approach (at s_min, distance b_miss). A crossing
            // well before that is pre-bend; s_min <= 0 means the ray
            // recedes from the hole its whole life and never bends.
            let s_min = -dot(cam_pos, ray_dir);
            let b_miss = length(cam_pos + ray_dir * max(s_min, 0.0));
            var w = 1.0;
            if s_min > 0.0 {
                w = smoothstep(0.5, 1.5, (s_min - t_cross) / max(b_miss, 1.0));
            }
            // Strong-field crossings (a few r_s from the hole) stay with
            // the bake regardless.
            w *= smoothstep(1.8, 2.6, r_a);
            if w > 0.001 {
                let inv = 1.0 / max(length(p.xz), 1e-5);
                c1_rr = mix(c1_r, r_a, w);
                c1_car = mix(c1_ca, p.x * inv, w);
                c1_sar = mix(c1_sa, p.z * inv, w);
                c1_vis_r = max(c1_visible, w);
            }
        }
    }
    let c2_mag2 = c2_ca * c2_ca + c2_sa * c2_sa;
    let c2_visible = smoothstep(0.25, 0.85, c2_mag2);

    // ── Composite back-to-front along the ray ──
    // Ray order: camera → front crossing → photon sphere → back
    // crossing → sky. So build the image sky-first and let each nearer
    // layer attenuate what's behind it by its own material alpha.

    // Star field. sky.w is the escaped/absorbed flag from the bake —
    // smoothstepped (not thresholded) so the gaussian-blurred shadow
    // boundary stays soft.
    var color = vec3<f32>(0.0);
    let escape_w = smoothstep(0.15, 0.65, sky.w);
    if escape_w > 0.001 {
        color = star_field(normalize(sky.xyz), u.stars_brightness) * escape_w;
    }

    // Lensed back of the disk — the arc that folds over and under the
    // shadow. Full brightness: this arc is the Interstellar signature,
    // not a background element (it was previously dimmed to 0.4×).
    if c2_r > 0.1 && c2_visible > 0.001 {
        let s2 = shade_disk(c2_r, c2_ca, c2_sa);
        let a2 = s2.alpha * c2_visible;
        color = color * (1.0 - a2) + s2.emission * c2_visible;
    }

    // Photon ring — light wound around the photon sphere. Thin and
    // genuinely bright (it's the jewel of the look); the front disk
    // composites over it afterwards, so it correctly hides behind
    // dense foreground filaments and shines through translucent ones.
    //
    // Width is normalized by the local screen-space gradient of final_r
    // (one extra tap per axis): the raw value-space gaussian's screen
    // width equals the width of the bake's blurred transition zone, so
    // it magnified into a fat fuzzy donut at close camera distances.
    // Gradient-normalized, the ring is a constant fraction of frame
    // height at every zoom.
    if final_r > 1.0 && final_r < 5.0 {
        // Gradient over a 2px baseline: final_r lives in an f16 texture,
        // and a 1px central difference amplifies its quantization into
        // visible grain once normalized.
        let texel = 2.0 / vec2<f32>(f32(dims.x), f32(dims.y));
        let fr_dx = textureSampleLevel(deflection1, s_linear, uv + vec2<f32>(texel.x, 0.0), 0.0).r;
        let fr_dy = textureSampleLevel(deflection1, s_linear, uv + vec2<f32>(0.0, texel.y), 0.0).r;
        let grad = max(length(vec2<f32>(fr_dx - final_r, fr_dy - final_r)) * 0.5, 1e-4);
        // Width tracks the shadow's on-screen scale (pixels per r_s at
        // the hole's distance), so the ring stays a proportionally thin
        // image feature at every zoom; the floor keeps it from aliasing
        // away when the hole is tiny in frame.
        let px_per_rs = f32(dims.y)
            / max(2.0 * u.uv_scale * fov_factor * safe_cam_dist, 1e-3);
        let half_w = clamp(0.18 * px_per_rs, 1.5, f32(dims.y) * 0.08);
        let dist_px = abs(final_r - 1.5) / grad;
        let ring = exp(-(dist_px * dist_px) / (half_w * half_w));
        color += vec3<f32>(1.25, 1.12, 0.92) * ring * 1.4;
    }

    // ── Volumetric emission (path integral through disk atmosphere) ──
    // vol_accum from the bake is non-zero for any ray passing near the
    // disk plane, and the gaussian blur smears it outward — gated by
    // c1_visible so it only contributes where the ray actually crosses
    // the disk silhouette (ungated it paints a warm halo on the sky).
    // Bounded by radial_envelope(vol_r): the bake integrates over its
    // fixed generous bounds, so without this the term paints a smooth
    // saucer-shaped halo out to r≈25 — the single biggest cause of the
    // old "hard disc" look.
    let vol = d2.r;
    if vol > 0.01 && c1_vis_r > 0.001 {
        let vol_opacity = 1.0 - exp(-vol * 0.3);
        let vol_r = select(c1_rr, (u.disk_inner + u.disk_outer) * 0.5, c1_rr < 0.1);
        let vol_t = clamp(
            (vol_r - u.disk_inner) / (u.disk_outer - u.disk_inner), 0.0, 1.0);
        let vol_fade = smoothstep(0.0, 0.15, vol);
        color += disk_palette(vol_t) * vol_opacity * vol_fade
            * u.disk_glow * 0.18 * c1_vis_r * radial_envelope(vol_r);
    }

    // Front disk crossing — nearest material, composited last.
    if c1_rr > 0.1 && c1_vis_r > 0.001 {
        let s1 = shade_disk(c1_rr, c1_car, c1_sar);
        let a1 = s1.alpha * c1_vis_r;
        color = color * (1.0 - a1) + s1.emission * c1_vis_r;
    }

    // ── HDR output ──
    // No tonemapping in this shader. The output buffer is Rgba16Float
    // and the rest of the MANIFOLD pipeline (bloom prefilter, halation,
    // EDR display presenter) is fully HDR-aware — bright disk regions
    // are emitted well above 1.0 and bloom turns them into light.
    // Sanity floor only — guard against NaN or negative leakage.
    color = max(color, vec3<f32>(0.0));

    textureStore(output, gid.xy, vec4<f32>(color, 1.0));
}

// Black Hole — Kerr Deflection Map
// @pure
// Params-only kernel (no time, no texture reads, no state): the memoizer
// re-dispatches the ~150-step geodesic trace only when a camera/spin/scale
// param actually moves, instead of every frame.
//
// Traces null geodesics in Kerr spacetime (spinning black hole).
// At spin=0, reduces exactly to Schwarzschild.
//
// Physics:
//   - Schwarzschild gravitational acceleration: -1.5 h²/r⁵ pos
//   - Kerr frame-dragging: gravitomagnetic force a/r³ cross(ŷ, vel)
//   - Boyer-Lindquist radius for horizon check (oblate geometry)
//   - Event horizon: r_H = 0.5(1 + √(1 - a²)) in our units (r_s = 1)
//
// Output 1: (final_r, disk1_r, cos_angle1, sin_angle1)
// Output 2: (vol_accum, disk2_r, cos_angle2, sin_angle2)
// Output 3: (sky_dir.xyz, escaped_flag)

struct Uniforms {
    aspect: f32,
    cam_dist: f32,
    tilt_rad: f32,
    rotate_rad: f32,
    steps: f32,
    uv_scale: f32,
    spin: f32,
    cam_velocity: f32,
    cam_freefall: f32,
    roll_rad: f32,
    _pad1: f32,
    _pad2: f32,
};

@group(0) @binding(0) var<uniform> u: Uniforms;
@group(0) @binding(1) var output1: texture_storage_2d<rgba16float, write>;
@group(0) @binding(2) var output2: texture_storage_2d<rgba16float, write>;
@group(0) @binding(3) var output3: texture_storage_2d<rgba16float, write>;

// Fixed generous crossing bounds — covers full param ranges
const CROSS_INNER: f32 = 0.5;
const CROSS_OUTER: f32 = 25.0;

@compute @workgroup_size(16, 16)
fn cs_main(@builtin(global_invocation_id) gid: vec3<u32>) {
    let dims = textureDimensions(output1);
    if gid.x >= dims.x || gid.y >= dims.y {
        return;
    }

    let uv = (vec2<f32>(f32(gid.x), f32(gid.y)) + 0.5) / vec2<f32>(f32(dims.x), f32(dims.y));
    let ndc = (uv * 2.0 - 1.0) * u.uv_scale;
    let screen_flat = vec2<f32>(ndc.x * u.aspect, -ndc.y);
    // Camera roll — bank the frame around the view axis so the disk can
    // sit diagonally in shot (third camera axis next to tilt = elevation
    // and rotate = azimuth orbit).
    let cr = cos(u.roll_rad);
    let sr = sin(u.roll_rad);
    let screen = vec2<f32>(
        screen_flat.x * cr - screen_flat.y * sr,
        screen_flat.x * sr + screen_flat.y * cr,
    );

    // ── Kerr spin setup (needed up front for camera physics horizon clamp) ──
    let a = u.spin;
    let a2 = a * a;
    // Event horizon: r_H = M + √(M² - a²M²) where M=0.5 (r_s = 1)
    // = 0.5(1 + √(1 - a²))
    let r_horizon = 0.5 * (1.0 + sqrt(max(1.0 - a2, 0.0)));
    let spin_axis = vec3<f32>(0.0, 1.0, 0.0);

    // ── Camera physics ──
    // The camera is allowed to fly through the event horizon for the trippy
    // "fall into a black hole" effect. The clamp here is purely numerical
    // safety to keep ratios finite very near the singularity — physical
    // correctness is not enforced inside the horizon (real observers can't
    // hover there, but this is a visual tool).
    let safe_cam_dist = max(u.cam_dist, 0.05);
    let camera_inside_horizon = safe_cam_dist < r_horizon;

    // ZAMO (Zero Angular Momentum Observer) frame correction.
    // Outside the horizon: the proper-frame solid angle subtended by infinity
    // shrinks by ≈ √(1 − r_s/r), so the aperture widens by 1/that to keep
    // distant features at a consistent angular size as the camera descends.
    // Inside the horizon: 1 − r_s/r is negative, the max() floor keeps the
    // metric factor at its minimum (0.05), giving a fully-saturated wide
    // aperture (~5×) for the "fallen in" view.
    let metric_factor = sqrt(max(1.0 - 1.0 / safe_cam_dist, 0.05));
    let fov_factor = 1.2 / metric_factor;

    // Gravitational redshift between observer at safe_cam_dist and infinity.
    // Stored multiplied into final_r so the display pass can dim escaping
    // light by the correct amount when the camera is deep in the well.
    let redshift_factor = metric_factor;

    let cos_tilt = cos(u.tilt_rad);
    let sin_tilt = sin(u.tilt_rad);
    let cos_rot = cos(u.rotate_rad);
    let sin_rot = sin(u.rotate_rad);

    let cam_pos = vec3<f32>(
        safe_cam_dist * cos_tilt * cos_rot,
        safe_cam_dist * sin_tilt,
        safe_cam_dist * cos_tilt * sin_rot,
    );
    let fwd = normalize(-cam_pos);
    let world_up = vec3<f32>(0.0, 1.0, 0.0);
    let right = normalize(cross(fwd, world_up));
    let up = cross(right, fwd);

    var ray_dir = normalize(fwd + screen.x * right * fov_factor + screen.y * up * fov_factor);

    // ── Relativistic aberration ──
    // Compose ZAMO → freefall-observer frame with a pure SR boost.
    // The observer's velocity is radial-inward (v̂ = fwd). In the
    // moving observer's frame, rays are pulled toward the forward
    // direction, so to convert a moving-frame ray to its ZAMO-frame
    // equivalent we use the INVERSE aberration transform:
    //
    //     cos θ = (cos θ' − β) / (1 − β cos θ')
    //
    // where θ is the angle between the ray and v̂ in the ZAMO frame
    // and θ' is the same angle in the moving frame.
    //
    // Cinematic mode: β = user slider (cam_velocity).
    // Freefall mode: β = √(r_s/r) (radial infall from rest at infinity),
    // clamped to 0.99 to keep the formula well-defined.
    var beta = u.cam_velocity;
    if u.cam_freefall > 0.5 {
        beta = clamp(sqrt(1.0 / safe_cam_dist), 0.0, 0.99);
    }
    if beta > 1e-4 {
        let v_dir = fwd; // radial-inward at cam_pos
        let cos_tp = dot(ray_dir, v_dir);
        let denom = 1.0 - beta * cos_tp;
        let cos_t = (cos_tp - beta) / denom;
        // Perpendicular component scaling: sin θ / sin θ'. Derivable
        // from requiring |ray_dir_static| = 1.
        let sin_tp2 = max(1.0 - cos_tp * cos_tp, 0.0);
        let sin_t2 = max(1.0 - cos_t * cos_t, 0.0);
        let perp_scale = select(
            1.0,
            sqrt(sin_t2 / sin_tp2),
            sin_tp2 > 1e-8,
        );
        let ray_perp = ray_dir - v_dir * cos_tp;
        ray_dir = normalize(v_dir * cos_t + ray_perp * perp_scale);
    }

    var pos = cam_pos;
    var vel = ray_dir;
    let h_vec = cross(pos, vel);
    let h2 = dot(h_vec, h_vec);

    let max_steps = i32(u.steps);
    let escape_r = max(safe_cam_dist * 3.0, 40.0);
    let base_step = max(safe_cam_dist * 0.02, 0.15);

    var prev_y = pos.y;
    var final_r = 0.0;
    var absorbed = false;

    var c1_r = 0.0; var c1_ca = 0.0; var c1_sa = 0.0;
    var c2_r = 0.0; var c2_ca = 0.0; var c2_sa = 0.0;
    var crossing_count = 0;
    var vol_accum = 0.0;

    for (var i = 0; i < max_steps; i++) {
        let r = length(pos);

        // Boyer-Lindquist radius (accounts for oblate Kerr horizon geometry)
        let w2 = r * r - a2;
        let r_bl = sqrt(max(0.5 * w2 + sqrt(max(0.25 * w2 * w2
            + a2 * pos.y * pos.y, 0.0)), 1e-8));

        // Singularity check — terminate any ray that reaches the center.
        // This also prevents 1/r⁵ NaNs in the gravitational acceleration.
        if r < 0.1 { final_r = 0.0; absorbed = true; break; }

        // Horizon absorption — only applied when the camera is OUTSIDE the
        // horizon. If the camera is inside, every ray starts inside the
        // horizon by definition, and we don't want them all self-absorbing
        // at step 0; let them fall to the singularity instead.
        if !camera_inside_horizon && r_bl < r_horizon {
            final_r = 0.0; absorbed = true; break;
        }

        if r > escape_r { final_r = r; break; }
        // Early escape: ray well beyond camera and moving outward — negligible bending
        if r > max(safe_cam_dist * 2.0, 15.0) && dot(pos, vel) > 0.0 {
            final_r = r; break;
        }

        let step = base_step * clamp(r * 0.1, 0.005, 2.0);

        // ── Schwarzschild gravitational acceleration ──
        let r2 = r * r;
        let r5 = r2 * r2 * r;
        let accel_grav = -1.5 * h2 / r5 * pos;

        // ── Kerr frame-dragging (gravitomagnetic force) ──
        // Photons are dragged in the direction of black hole rotation.
        // Force ∝ a/r³, direction = cross(spin_axis, vel).
        // At a=0 this is zero → identical to Schwarzschild.
        let r3 = r2 * r;
        let accel_drag = a / r3 * cross(spin_axis, vel);

        let accel = accel_grav + accel_drag;

        // Verlet first half-step
        vel += accel * step * 0.5;
        pos += vel * step;

        // Verlet second half-step (recompute at new position)
        let r_new = length(pos);
        let r2_new = r_new * r_new;
        let r5_new = r2_new * r2_new * r_new;
        let accel_grav2 = -1.5 * h2 / r5_new * pos;
        let r3_new = r2_new * r_new;
        let accel_drag2 = a / r3_new * cross(spin_axis, vel);
        vel += (accel_grav2 + accel_drag2) * step * 0.5;

        // ── Volumetric density accumulation ──
        // Gaussian vertical profile: rays near the disk plane accumulate density.
        // Path integral gives volumetric thickness for edge-on viewing.
        let disk_r_xz = length(vec2<f32>(pos.x, pos.z));
        if disk_r_xz > CROSS_INNER && disk_r_xz < CROSS_OUTER {
            let half_thick = 0.12 * disk_r_xz;
            let y_norm = pos.y / half_thick;
            vol_accum += exp(-y_norm * y_norm * 2.0) * step;
        }

        // ── Disk crossing detection ──
        let cur_y = pos.y;
        if prev_y * cur_y < 0.0 {
            let frac = abs(prev_y) / (abs(prev_y) + abs(cur_y) + 1e-8);
            let cross_pos = pos - vel * step * (1.0 - frac);
            let cross_r = length(cross_pos);

            if cross_r > CROSS_INNER && cross_r < CROSS_OUTER {
                let angle = atan2(cross_pos.z, cross_pos.x);
                let ca = cos(angle);
                let sa = sin(angle);

                if crossing_count == 0 {
                    c1_r = cross_r; c1_ca = ca; c1_sa = sa;
                } else if crossing_count == 1 {
                    c2_r = cross_r; c2_ca = ca; c2_sa = sa;
                }
                crossing_count++;
            }
        }
        prev_y = cur_y;
        final_r = r;
    }

    // Apply gravitational redshift to the escape radius — the photon ring
    // and far-field intensity dim by metric_factor when the camera is deep
    // in the well.
    let final_r_redshifted = final_r * redshift_factor;
    textureStore(output1, gid.xy, vec4<f32>(final_r_redshifted, c1_r, c1_ca, c1_sa));
    textureStore(output2, gid.xy, vec4<f32>(vol_accum, c2_r, c2_ca, c2_sa));

    if absorbed {
        textureStore(output3, gid.xy, vec4<f32>(0.0, 0.0, 0.0, 0.0));
    } else {
        let sky_dir = normalize(vel);
        textureStore(output3, gid.xy, vec4<f32>(sky_dir, 1.0));
    }
}
